 const NETWORK_ERRORS: Record<string, Omit<ClassifiedError, "statusCode">> = {
   ECONNREFUSED: {
     title: "Connection Refused",
     description: "Could not connect to the server.",
     icon: Wifi,
     category: "network",
   },
   ECONNRESET: {
