             {opt}
           </button>
         ))}
       </div>
     );
   }

   if (question.type === "slider" && typeof question.min === "number" && typeof question.max === "number") {
     const numValue = value ? parseFloat(value) : question.min;
     return (
       <div className="space-y-2">
         <input
           type="range"
           min={question.min}
           max={question.max}
