               {activeQuestion && (
-                <div className="mx-auto mb-2 w-[calc(100%-6px)] max-w-3xl sm:w-full">
+                <div className="mx-auto mb-1.5 sm:mb-2 w-[calc(100%-6px)] max-w-3xl sm:w-full">
                   <QuestionRenderer
                     data={activeQuestion}
                     onSubmit={(answers) => {
                       window.dispatchEvent(
